// Modernize this code — same output, ES6+ syntax
var crew = [
  { name: "Grace", role: "scientist", status: "active" },
  { name: "Ilyukhina", role: "commander" }
];

function formatMember(member) {
  var name = member.name;
  var role = member.role;
  var status = member.status || "unknown";
  return name + " (" + role + ") — " + status;
}

var formatted = crew.map(function(m) {
  return formatMember(m);
});

challenges.solution:
const crew = [
  { name: "Grace", role: "scientist", status: "active" },
  { name: "Ilyukhina", role: "commander" }
];

const formatMember = ({ name, role, status = "unknown" }) =>
  `${name} (${role}) — ${status}`;

const formatted = crew.map(formatMember);
